bash_commands.command:
cat > /workspace/review.json << 'EOF'
[
  {
    "file": "clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java",
    "line": 121,
    "severity": "critical",
    "description": "Missing token expiry validation. When token authentication is used, the token's expiry timestamp is obtained from the callback but never validated. A token that has already expired will be accepted, allowing authentication bypass.",
    "fix_patch": "--- a/clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java
+++ b/clients/src/main/java/org/apache/kafka/common/security/scram/internals/ScramSaslServer.java
@@ -118,7 +118,11 @@
                             callbackHandler.handle(new Callback[]{nameCallback, tokenCallback});
                             if (tokenCallback.tokenOwner() == null)
                                 throw new SaslException("Token Authentication failed: Invalid tokenId : " + username);
                             this.authorizationId = tokenCallback.tokenOwner();
-                            this.tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
+                            Long tokenExpiryTimestamp = tokenCallback.tokenExpiryTimestamp();
+                            if (tokenExpiryTimestamp != null && tokenExpiryTimestamp < System.currentTimeMillis()) {
+                                throw new SaslException("Token has expired");
+                            }
+                            this.tokenExpiryTimestamp = tokenExpiryTimestamp;
                         } else {
                             credentialCallback = new ScramCredentialCallback();
                             callbackHandler.handle(new Callback[]{nameCallback, credentialCallback});
"
  },
  {
    "file": "core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala",
    "line": 377,
    "severity": "critical",
    "description": "Authorization bypass via shouldAllowEveryoneIfNoAclIsFound configuration. The check for this config occurs before calculating denyPrefixes, allowing access even when deny prefix ACLs exist. An attacker can bypass prefix-based deny rules by exploiting this logic gap.",
    "fix_patch": "--- a/core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala
+++ b/core/src/main/scala/kafka/security/authorizer/AclAuthorizer.scala
@@ -369,13 +369,6 @@
       return AuthorizationResult.DENIED
     }

-    if (shouldAllowEveryoneIfNoAclIsFound) {
-      logAuditMessage(requestContext, action, authorized = true)
-      return AuthorizationResult.ALLOWED
-    }
-
     val denyPrefixes = matchingResources(
       resourceSnapshot, principalStr, host, op, AclPermissionType.DENY, resourceType, PatternType.PREFIXED)

@@ -385,7 +378,8 @@
         logAuditMessage(requestContext, action, authorized = true)
         return AuthorizationResult.ALLOWED
       } else {
-        logAuditMessage(requestContext, action, authorized = false)
-        return AuthorizationResult.DENIED
+        logAuditMessage(requestContext, action, authorized = shouldAllowEveryoneIfNoAclIsFound)
+        return if (shouldAllowEveryoneIfNoAclIsFound) AuthorizationResult.ALLOWED else AuthorizationResult.DENIED
       }
     }

"
  }
]
EOF
cat /workspace/review.json

